<?php

if ( ! defined( 'ABSPATH' ) ) {
    exit;
}    // Exit if accessed directly


/**
 * Locations map shortcode
 * [map]
 *
 * Relies on Advanced Custom Fields 'sites' repeater field
 */
add_shortcode( 'map', 'map_shortcode_fxn' );

